 const _20250605FacebookNestPasUnGrin = "{\"parsed\":{\"_path\":\"/fr/20250605-facebook-nest-pas-un-grin\",\"_dir\":\"fr\",\"_draft\":false,\"_partial\":false,\"_locale\":\"\",\"title\":\"Quand un Community Manager confond réseaux sociaux et le Grin\",\"description\":\"Penser avec rigueur, respecter autrui, peser ses mots : autant de qualités qu'on attend d'un professionnel — surtout dans un secteur aussi symbolique que le livre et la communication. Je ne suis pas ici pour faire la morale, mais pour rappeler que les réseaux sociaux ne sont pas un grin — ce groupe informel de discussion entre amis où l'on débat de tout et de rien, souvent sans fond ni filtre. Mais parfois, on a l'impression que certains professionnels ont oublié ces notions de base.\",\"image\":\"/images/articles/bescherelle/01.jpg\",\"createdAt\":\"2025-06-05\",\"id\":\"2025-06-05T00:00:00.000Z\",\"keywords\":\"community manager, réseaux sociaux, sexisme, Abidjan,  féminisme, critique sociale\",\"summary\":\"Penser avec rigueur, respecter autrui, peser ses mots : autant de qualités qu'on attend d'un professionnel — surtout dans un secteur aussi symbolique que le livre et la communication. Je ne suis pas ici pour faire la morale, mais pour rappeler que les réseaux sociaux ne sont pas un grin — ce groupe informel de discussion entre amis où l'on débat de tout et de rien, souvent sans fond ni filtre. Mais parfois, on a l'impression que certains professionnels ont oublié ces notions de base.\",\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"h1\",\"props\":{\"id\":\"quand-un-community-manager-confond-réseaux-sociaux-et-grin\"},\"children\":[{\"type\":\"text\",\"value\":\"Quand un Community Manager confond réseaux sociaux et \\\"Grin\\\"\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Bonjour.\"}]}]},{\"type\":\"element\",\"tag\":\"iframe\",\"props\":{\"width\":560,\"height\":315,\"src\":\"https://www.youtube.com/embed/XBmb1g9j3Ac\",\"title\":\"YouTube video player\",\"frameBorder\":\"0\",\"allow\":\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\",\"allowFullScreen\":true},\"children\":[]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Je suis Jean-Luc Houédanou, développeur web et défenseur assumé du bon sens.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Penser avec rigueur, respecter autrui, peser ses mots : autant de qualités qu'on attend d'un professionnel — surtout dans un secteur aussi symbolique que le livre et la communication. Je ne suis pas ici pour faire la morale, mais pour rappeler que les réseaux sociaux ne sont pas un \"},{\"type\":\"element\",\"tag\":\"em\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"grin\"}]},{\"type\":\"text\",\"value\":\" — ce groupe informel de discussion entre amis où l'on débat de tout et de rien, souvent sans fond ni filtre.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Mais parfois, on a l'impression que certains professionnels ont oublié ces notions de base.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"un-retour-en-arrière-consternant\"},\"children\":[{\"type\":\"text\",\"value\":\"Un retour en arrière consternant\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Récemment, un community manager d'une structure bien connue du secteur littéraire ivoirien a cru bon de commenter la maîtrise du français chez les femmes de manière pour le moins... maladroite.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Sa \\\"solution\\\" : offrir un Bescherelle, non sans une pointe de sarcasme.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"img\",\"props\":{\"alt\":\"Commentaire sexiste du community manager sur les femmes et les iPhone\",\"src\":\"/images/articles/bescherelle/01.jpg\"},\"children\":[]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Une réaction qui, au-delà du mépris affiché, illustre un mélange regrettable d'arrogance et de méconnaissance grammaticale.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Et c'est là que le bât blesse.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"quand-on-veut-corriger-mieux-vaut-être-irréprochable\"},\"children\":[{\"type\":\"text\",\"value\":\"Quand on veut corriger, mieux vaut être irréprochable\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Exemple concret : « Ce qu'elles nous servent là est affreux ».\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Cette tournure, en plus d'être condescendante, repose sur une utilisation hasardeuse du verbe \\\"servir\\\".\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"On ne \\\"sert\\\" pas une erreur de grammaire comme on sert un café. Cette formulation maladroite, pourtant employée pour critiquer la langue des autres, révèle une maîtrise imparfaite du français — un comble, pour quelqu'un qui a la prétention de distribuer des Bescherelle.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Ensuite, il y a ceci.\"}]},{\"type\":\"element\",\"tag\":\"blockquote\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"« Allure de princesses, démarche de déesses, tête d'illettrés. Dehors ! Partagez au max, elles doivent voir. »\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"À première vue, on sent la volonté de \\\"faire une formule choc\\\". Mais en regardant de plus près, on constate que le style et la grammaire ne suivent pas toujours l'intention.\\nQuelques observations :\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Tête d'illettrés\\\" : ici, le mot illettrés est au masculin pluriel, alors que le sujet de la phrase est féminin (\\\"elles\\\"). La bonne tournure serait donc tête d'illettrées.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Il y a aussi un souci de cohérence stylistique : on aligne \\\"allure\\\", \\\"démarche\\\" et \\\"tête\\\" dans une même structure, mais avec des images de registres différents, ce qui crée un effet bancal.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Ce qui devait être une critique sur la maîtrise du français se retourne donc contre son auteur : on ne peut pas corriger les autres en oubliant les accords de base. Et surtout, il n'est jamais pertinent de porter un jugement aussi général, encore moins sur un ton méprisant, quand on s'adresse à un public large – et potentiellement jeune – depuis une page institutionnelle.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"lironie-de-la-posture-critique\"},\"children\":[{\"type\":\"text\",\"value\":\"L'ironie de la posture critique\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"On assiste ici à un glissement regrettable : le rôle du community manager, censé valoriser une institution et porter des messages culturels, devient un espace de règlement de comptes personnel, teinté de clichés sexistes et de jugements hasardeux.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Quelques exemples de ses \\\"perles\\\" :\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"img\",\"props\":{\"alt\":\"Commentaire sexiste du community manager\",\"src\":\"/images/articles/bescherelle/03.jpg\"},\"children\":[]},{\"type\":\"element\",\"tag\":\"img\",\"props\":{\"alt\":\"Autre exemple de commentaire problématique\",\"src\":\"/images/articles/bescherelle/04.jpg\"},\"children\":[]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"On tient là une façon de penser empruntée aux codes de la manosphère.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pour ceux qui ne connaissent pas encore cet univers particulier, j'avais déjà exploré les eaux troubles de la manosphère dans \"},{\"type\":\"element\",\"tag\":\"a\",\"props\":{\"href\":\"https://jeanluchouedanou.blogspot.com/2023/04/ma-plongee-dans-les-eaux-troubles-de-la.html\",\"rel\":[\"nofollow\"]},\"children\":[{\"type\":\"text\",\"value\":\"un précédent article\"}]},{\"type\":\"text\",\"value\":\".\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"(\"},{\"type\":\"element\",\"tag\":\"em\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Spoiler : 2 ans plus tard, ça n'a pas vieilli.\"}]},{\"type\":\"text\",\"value\":\")\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Prochaine étape logique : interdire aux femmes l'accès aux bibliothèques le vendredi soir, ou juste leur permettre l'accès aux rayons \\\"romance\\\" et \\\"développement personnel\\\" à droite pour \\\"les filles qui rêvent\\\", les essais politiques et \"},{\"type\":\"element\",\"tag\":\"em\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Les 48 lois du pouvoir\"}]},{\"type\":\"text\",\"value\":\" à gauche pour \\\"les vrais penseurs\\\", les mâles alpha.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"un-appel-à-mieux-faire\"},\"children\":[{\"type\":\"text\",\"value\":\"Un appel à mieux faire\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Ce n'est pas un procès, mais un appel au professionnalisme et au respect.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Il faut le souligner : ce n'est pas la librairie dans son ensemble qui s'est exprimée. D'ailleurs, cette dernière afait une mise au point ferme , que je salue.\\n\"},{\"type\":\"element\",\"tag\":\"img\",\"props\":{\"alt\":\"Mise au point de la librairie\",\"src\":\"/images/articles/bescherelle/00.jpg\"},\"children\":[]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"C'est juste un(e) CM — mal formé(e) ou mal encadré(e) — qui, en quelques clics, a transformé une vitrine culturelle en scène de stand-up misogyne.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"En conclusion, mesdames, soyez vous-mêmes.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"C'est précisément ce qui dérange certains — et c'est une bonne chose.\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[{\"id\":\"un-retour-en-arrière-consternant\",\"depth\":2,\"text\":\"Un retour en arrière consternant\"},{\"id\":\"quand-on-veut-corriger-mieux-vaut-être-irréprochable\",\"depth\":2,\"text\":\"Quand on veut corriger, mieux vaut être irréprochable\"},{\"id\":\"lironie-de-la-posture-critique\",\"depth\":2,\"text\":\"L'ironie de la posture critique\"},{\"id\":\"un-appel-à-mieux-faire\",\"depth\":2,\"text\":\"Un appel à mieux faire\"}]}},\"_type\":\"markdown\",\"_id\":\"content:fr:20250605-facebook-nest-pas-un-grin.md\",\"_source\":\"content\",\"_file\":\"fr/20250605-facebook-nest-pas-un-grin.md\",\"_stem\":\"fr/20250605-facebook-nest-pas-un-grin\",\"_extension\":\"md\",\"sitemap\":{\"loc\":\"/fr/20250605-facebook-nest-pas-un-grin\"}},\"hash\":\"ybo3XWQ2TI\"}";

